import axios from 'axios';

const api = {
  baseURL: 'https://api.example.com',
};

// Define a function to handle authentication
function authenticate(username, password) {
  const authConfig = {
    method: 'POST',
    url: `${api.baseURL}/authenticate`,
    headers: {
      Accept: 'application/json',
      'Content-Type': 'application/json',
    },
    data: JSON.stringify({ username, password }),
  };

  return axios(authConfig);
}

// Define a function to fetch user profile
function getUserProfile() {
  const config = {
    method: 'GET',
    url: `${api.baseURL}/users/me`,
    headers: {
      Accept: 'application/json',
      Authorization: `Bearer ${localStorage.getItem('token')}`,
    },
  };

  return axios(config);
}

// Define a function to update user data
function updateUserProfile(data) {
  const config = {
    method: 'PUT',
    url: `${api.baseURL}/users/me`,
    headers: {
      Accept: 'application/json',
      Authorization: `Bearer ${localStorage.getItem('token')}`,
      'Content-Type': 'application/json',
    },
    data,
  };

  return axios(config);
}

export { authenticate, getUserProfile, updateUserProfile };